@app.route("/orders", methods=["POST"])
def create_order():
    order_value = float(request.json.get("value", random.uniform(20, 500))) if request.is_json else random.uniform(20, 500)
    status = request.json.get("status", "success") if request.is_json else "success"

    BUSINESS_ORDERS_CREATED.labels(status=status).inc()
    BUSINESS_ORDER_VALUE.observe(order_value)

    queue_depth = random.randint(0, 100)
    BUSINESS_QUEUE_DEPTH.labels(queue_name="orders").set(queue_depth)

    active_users = random.randint(50, 500)
    BUSINESS_ACTIVE_USERS.set(active_users)

    return jsonify(
        {
            "message": "order created",
            "status": status,
            "value": order_value,
            "queue_depth": queue_depth,
            "active_users": active_users,
        }
    ), 201


@app.route("/payments/process", methods=["POST"])
def process_payment():
    start = time.perf_counter()
    time.sleep(random.uniform(0.01, 0.2))
    result = request.json.get("result", "success") if request.is_json else "success"

    BUSINESS_PAYMENTS_PROCESSED.labels(result=result).inc()
    BUSINESS_PAYMENT_LATENCY.observe(time.perf_counter() - start)

    return jsonify({"message": "payment processed", "result": result})


@app.route("/inventory/<product_id>", methods=["POST"])
def update_inventory(product_id):
    level = int(request.json.get("level", random.randint(0, 1000))) if request.is_json else random.randint(0, 1000)
    BUSINESS_INVENTORY_LEVEL.labels(product_id=product_id).set(level)
    return jsonify({"product_id": product_id, "inventory_level": level})


